-- Enrichment marathon batch: SPIP, Spline, SpotDraft, SpotMe, SpotOn, Spreaker, Spree Commerce, Sprinto

-- ── SPIP ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SPIP is a free, open-source content management system created in France for building collaborative, multilingual websites without deep technical expertise.$q$, short_description),
  pricing_model = COALESCE($q$open-source/free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$French$q$, $q$English$q$, $q$Spanish$q$, $q$German$q$, $q$Italian$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$SPIP: Free Open-Source CMS for Collaborative Publishing$q$, seo_title),
  seo_meta_description = COALESCE($q$SPIP is a free, open-source French CMS built for collaborative, multilingual website publishing. See features, pricing, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SPIP (Systeme de Publication pour l'Internet Partage) is a free, open-source content management system first released on July 1, 2001 by the minirezo collective in France. It was built to let journalists, associations, and webmasters publish and structure articles collaboratively without needing deep technical skills. SPIP is distributed under the GNU General Public License, so it can be downloaded, self-hosted, modified, and redistributed at no cost for personal, nonprofit, institutional, or commercial sites. The platform is especially popular in the French-speaking web and has been used by organizations such as Le Monde diplomatique for multilingual editorial workflows. SPIP ships with strong multilingual publishing support, covering more than 20 interface languages, and a plugin ecosystem for extending templates, forms, and site structure. There is no vendor company behind SPIP; it is maintained by a volunteer community of developers, documentation writers, and translators who coordinate through open forums and mailing lists. Because it is self-hosted, users are responsible for their own server, so total cost depends on hosting rather than software licensing. SPIP suits users who want an editorially focused, collaborative publishing tool and are comfortable with (or want to avoid) the complexity of larger CMS platforms like WordPress or Drupal.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f7206e3a-e992-4f4e-b237-ddd3af5fbec1';

