-- ── Spline ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Spline is a browser-based 3D design tool that lets designers and developers create, animate, and publish interactive 3D scenes for the web without a traditional 3D pipeline.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $12/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Spline: Browser-Based 3D Design and Animation Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Spline is a real-time 3D design tool for interactive scenes, product visuals, and web animation. Compare pricing plans, features, pros, and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Spline is a browser-based 3D design and animation platform founded in 2020 by Alejandro Leon, Andrei Linkov, and Vadim Konstantinov, and backed by Y Combinator. It lets designers, developers, and marketing teams create interactive 3D scenes, product visuals, and web experiences without needing a traditional 3D software pipeline like Blender or Cinema 4D. Spline runs entirely in the browser, supports real-time multiplayer collaboration similar to Figma, and can export projects as code (including React Three Fiber components), images, video, or embeddable web widgets. It also offers an AI add-on for text-to-3D and image-to-3D generation, plus AI texture and style transfer tools. Pricing follows a freemium model: a free plan supports limited files with watermarked web exports, a Starter plan starts at $12 per month billed annually (or $15 monthly) removing watermarks and unlocking unlimited files, a Professional plan is $20 per month billed annually (or $25 monthly) adding code export and unlimited scenes, and an Enterprise plan offers custom pricing with SSO, self-hosted exports, and dedicated support. Spline has raised over $41 million in funding, including a 2024 Series A, and is used by design and marketing teams to build interactive 3D landing pages, product configurators, and animated web content.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fdd5fb34-6747-4479-81aa-8ae793ce0279';

