-- ── SpotDraft ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SpotDraft is an AI-native contract lifecycle management platform that helps legal, sales, and procurement teams draft, negotiate, sign, and manage contracts in one system.$q$, short_description),
  pricing_model = COALESCE($q$subscription (quote-based)$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Bengaluru, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SpotDraft: AI Contract Lifecycle Management Software$q$, seo_title),
  seo_meta_description = COALESCE($q$SpotDraft is an AI-native CLM platform for drafting, negotiating, signing, and managing contracts. See features, pricing model, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SpotDraft is a contract lifecycle management (CLM) platform founded in 2017 by Shashank Bijapur and Madhav Bhagat, headquartered in Bengaluru, India with an additional office in New York. The platform helps in-house legal, sales, procurement, and HR teams manage the full contract lifecycle, from templated drafting and AI-assisted redlining through e-signature, approval workflows, and a searchable contract repository. SpotDraft markets itself as an AI-native CLM, positioning its automation around faster contract turnaround, with the company citing benchmarks such as contracts closing twice as fast and roughly 65 percent lower costs for customers. Pricing is not published; SpotDraft uses a custom, quote-based model billed per active user or by contract volume, with implementation, integrations, and 24 by 7 support included at no extra charge. The company has raised approximately 82 million dollars in funding, including a 54 million dollar Series B in February 2025 led by Vertex Growth Fund, and has stated it is profitable. SpotDraft primarily serves small and mid-market businesses with in-house legal teams that want structured contract workflows without heavy enterprise complexity, though it also supports larger enterprise customers through custom plans.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e12cbfc9-d246-4893-93a6-78ac5fffa567';

