-- ── SpotMe ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SpotMe is an enterprise event management platform used by life sciences, professional services, and technology companies to run virtual, hybrid, and in-person events.$q$, short_description),
  pricing_model = COALESCE($q$subscription (quote-based)$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Lausanne, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SpotMe: Enterprise Event Management Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$SpotMe is an enterprise event platform for virtual, hybrid, and in-person events, built for life sciences and professional services. See plans and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SpotMe is an enterprise event management platform founded in 2000 as a spin-off from EPFL in Lausanne, Switzerland, where it remains headquartered today, with additional offices in Chicago, Sofia, and Singapore. Originally a hardware networking device company, SpotMe transformed into a SaaS event app platform in 2011 and has since focused heavily on enterprise customers in regulated industries such as life sciences, alongside professional services and technology companies. In April 2023, Swiss Post acquired a majority stake in SpotMe while the company continued to operate independently. The platform supports virtual, hybrid, and in-person events through a single system, offering more than 80 engagement features including streaming, breakout sessions, a studio for speakers, polls, gamification, and networking tools. A dedicated offering, Onomi, extends SpotMe's event technology for life sciences customer engagement and compliance needs. Pricing is quote-based across four tiers, Starter, Business, Advanced, and Enterprise, distinguished mainly by the number of events included, integration availability, and app branding options; SpotMe does not publish fixed prices and pricing does not scale with the number of event participants. SpotMe has been recognized as an event technology leader by G2 and Forrester.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f78d10ab-b34b-493a-9c96-2e256f6d8c27';

