-- ── SpotOn ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SpotOn is a restaurant and small-business technology company offering point-of-sale systems, payment processing, online ordering, and business management tools.$q$, short_description),
  pricing_model = COALESCE($q$subscription plus transaction fees$q$, pricing_model),
  starting_price = COALESCE($q$$0/month software (plus payment processing rates)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$1,001-5,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SpotOn: Restaurant POS and Payments Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$SpotOn provides restaurant POS, payment processing, online ordering, and management tools. Compare pricing model, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SpotOn is a restaurant and small-business technology company founded in 2017 by Doron Friedman, Matt Hyman, and Zach Hyman, headquartered in San Francisco, California. The company builds an integrated ecosystem of point-of-sale hardware and software, payment processing, online ordering and delivery, reservation and waitlist management, labor scheduling, payroll integration, marketing and loyalty tools, and AI-powered profitability analysis, aimed primarily at restaurants across casual dining, fine dining, bars, breweries, quick-service, and cafes. It also offers SpotOn Terminal, a payments and POS solution for other small businesses such as retail, salons, and automotive services. SpotOn is privately held with backing from major investors including Dragoneer Investment Group, Andreessen Horowitz, 01 Advisors, DST Global, and Franklin Templeton, and has grown to more than 2,600 employees. SpotOn markets its POS software plans as starting at 0 dollars per month with competitive processing rates, though most restaurants use its Core Bundle package with pricing that varies by business needs and typically requires a custom quote or demo. The company has been ranked the number one restaurant POS by G2 for multiple consecutive quarters.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '17484540-c7ef-4a3f-b23f-5866c0cdd5ac';

