-- ── Spreaker ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Spreaker is a podcast hosting and monetization platform, owned by iHeartMedia, that lets creators publish, distribute, track, and monetize podcasts from one dashboard.$q$, short_description),
  pricing_model = COALESCE($q$freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from EUR20/month)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, NY, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$Spreaker: Podcast Hosting and Monetization Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Spreaker is a podcast hosting platform owned by iHeartMedia offering distribution, analytics, and monetization. Compare plans, features, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Spreaker is a podcast hosting and monetization platform founded in 2010 by Francesco Baschieri. In 2018, Spreaker merged with BlogTalkRadio to form Voxnest, and in 2020 iHeartMedia acquired Voxnest, bringing Spreaker under the iHeartMedia umbrella. The platform lets podcasters manage their RSS feed, automatically distribute episodes to major platforms like Spotify and Apple Podcasts, track listener analytics, and monetize shows through built-in advertising, subscriptions, and a Supporters Club membership feature. Spreaker offers a free-forever plan, Free Speech, that includes unlimited episodes and automatic ad monetization but takes a 20 percent fee on Supporters Club revenue and hosts only one podcast with 6 months of statistics. Paid plans scale up from Broadcaster at 20 euros per month, which adds unlimited podcasts and removes the Supporters Club fee, to Anchorman at 50 euros per month with full collaboration and statistics, up to Publisher at 250 euros per month, which adds an ad campaign manager for direct ad sales and IAB category blocking, aimed at professional broadcasters and media companies. Because of its iHeartMedia ownership, Spreaker also offers enterprise-level distribution and monetization infrastructure for high-volume podcast networks.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '41ee4232-5722-4e22-a602-9fdc2ae29ca2';

