-- ── Spree Commerce ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Spree Commerce is an open-source, headless e-commerce platform built on Ruby on Rails, offering a free self-hosted Community Edition and a paid Enterprise Edition for B2B and marketplace commerce.$q$, short_description),
  pricing_model = COALESCE($q$open-source (free) plus paid enterprise edition$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Spree Commerce: Open-Source Headless Ecommerce Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Spree Commerce is a free, open-source headless ecommerce platform on Ruby on Rails, with a paid Enterprise Edition for B2B and marketplace commerce.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Spree Commerce is an open-source, headless e-commerce platform built on Ruby on Rails, created by Sean Schofield in 2007. Its Community Edition is free and self-hosted under a BSD-3-Clause open-source license, providing a full storefront, product catalog, checkout, and REST APIs for direct-to-consumer stores, and it has surpassed 15,000 GitHub stars and 2.7 million RubyGems downloads. Spree was acquired by First Data in 2015 to expand into open-source commerce and payments technology, and the project has since continued development with a broad open-source contributor base of over 800 contributors; today, a team operating as Vendo maintains and develops Spree Commerce. Companies that have used Spree include Goop, Craftsman, Kenmore, Blue Bottle Coffee, Fortnum and Mason, and GoDaddy. Alongside the free Community Edition, Spree offers a commercially licensed Enterprise Edition with custom pricing that adds B2B commerce, multi-vendor marketplace, and multi-tenant white-label SaaS modules, plus a dedicated success manager, SLA-backed support, and enterprise security features like SSO and audit logging. Spree is aimed at developers and growing DTC brands that want full ownership of their commerce stack without vendor lock-in or recurring platform fees, and it supports multi-region, multi-currency, and multi-language stores out of the box.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '80d28886-f2f5-4191-a617-3ed3234eb862';

