-- ── Sprinto ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sprinto is a compliance automation platform that helps SaaS and technology companies achieve and maintain certifications like SOC 2, ISO 27001, GDPR, and HIPAA through continuous monitoring.$q$, short_description),
  pricing_model = COALESCE($q$subscription (quote-based)$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Bangalore, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sprinto: Automated SOC 2 and ISO 27001 Compliance$q$, seo_title),
  seo_meta_description = COALESCE($q$Sprinto automates SOC 2, ISO 27001, GDPR, and HIPAA compliance with continuous monitoring and evidence collection. See features, pricing, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sprinto is a compliance automation platform founded in 2020 by Girish Redekar and Raghuveer Kancherla, headquartered in Bangalore, India, with a growing presence in San Francisco and offices across multiple continents. The platform connects to a company's cloud infrastructure, identity providers, HR systems, and code repositories through APIs, then runs automated tests against frameworks such as SOC 2, ISO 27001, GDPR, and HIPAA, covering more than 200 frameworks and standards in total. It continuously collects timestamped evidence and surfaces a real-time compliance dashboard, reducing the manual screenshot-and-spreadsheet work traditionally required to prepare for security audits. Sprinto reports crossing 3,000 customers across 75 countries, supports more than 300 integrations, and launched an AI-driven compliance capability, Sprinto AI, in 2025. The company has raised venture funding including a 20 million dollar Series B round in April 2024. Pricing is not published on Sprinto's website and is quote-based, varying by company size and the number of frameworks pursued; third-party estimates suggest a single framework such as SOC 2 typically runs in the range of 6,000 to 10,000 dollars per year, with multi-framework or enterprise plans costing significantly more. Sprinto is aimed primarily at SaaS and technology companies that need to pass customer security reviews and maintain ongoing compliance without a large dedicated compliance team.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '01db3fa1-4544-4df3-b94a-c8779f0ed121';

