INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Collaborative editorial workflow$q$, $q$Role-based publishing states (draft, proposed, published) let writers, editors, and admins collaborate on articles with clear permissions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Native multilingual publishing$q$, $q$Built-in tools for maintaining and tracking translated content across more than 20 languages on a single site.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Template separation via SPIP loops$q$, $q$A custom templating language keeps content and design separate, so themes can be changed without touching site data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Plugin ecosystem$q$, $q$A community-maintained plugin directory extends SPIP with forums, newsletters, SEO tools, custom fields, and more.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Self-hosted and license-free$q$, $q$Runs on standard PHP and MySQL hosting with no software licensing fees under the GNU GPL.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Lightweight footprint$q$, $q$Designed to run efficiently on modest hosting, making it accessible to small associations and nonprofits.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Active community governance$q$, $q$Maintained by volunteer developers, documenters, and translators rather than a single commercial vendor.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Strong built-in support for multilingual and collaborative publishing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Long track record and mature codebase dating back to 2001$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Lightweight and runs well on modest hosting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Active French-language community and extensive plugin catalog$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Smaller international community and fewer English-language resources than WordPress or Drupal$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Steeper learning curve for its custom templating language$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$No official commercial support channel or SLA$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Plugin quality and maintenance varies since it is entirely community-driven$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Less common outside the French-speaking web, so fewer premium themes and integrations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Is SPIP really free$q$, $q$Yes. SPIP is licensed under the GNU General Public License, so it can be downloaded, installed, and modified at no cost for personal, nonprofit, or commercial use.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Who maintains SPIP$q$, $q$SPIP is maintained by an open-source community of developers, documentation writers, and translators rather than a single company, coordinated through public forums and mailing lists.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$What is SPIP best suited for$q$, $q$SPIP is best suited for editorial teams, associations, and institutions that need collaborative, multilingual publishing workflows rather than a general-purpose website builder.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Does SPIP support multiple languages$q$, $q$Yes. SPIP has native multilingual publishing tools and an interface translated into more than 20 languages, making it popular for sites that need parallel-language content.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Can I get paid support for SPIP$q$, $q$There is no official commercial vendor, but independent freelancers and agencies within the SPIP community offer paid development and support services.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$What technology does SPIP run on$q$, $q$SPIP is a PHP application typically paired with a MySQL database, and it can run on standard shared or managed web hosting.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$How does SPIP compare to WordPress$q$, $q$SPIP is more narrowly focused on collaborative editorial publishing and multilingual sites, while WordPress has a much larger plugin and theme ecosystem and broader general-purpose use.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Is SPIP still actively developed$q$, $q$Yes. SPIP continues to receive stable releases from its community, with recent versions in the 4.x series.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Association and nonprofit websites$q$, $q$Small organizations use SPIP to publish news and articles collaboratively without paying for software licenses.$q$, $q$Nonprofits and associations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Multilingual editorial publishing$q$, $q$Media outlets and institutions maintain parallel-language content with SPIP's built-in translation tracking.$q$, $q$Multilingual publishers and media organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Institutional and government sites$q$, $q$Public sector bodies in French-speaking regions use SPIP for its long track record, GPL licensing, and self-hosting control.$q$, $q$Public institutions and government agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full access to SPIP source code","Unlimited sites, users, and content","Community support via forums and mailing lists","GNU GPL open-source license"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$overview$q$, $q$What Is SPIP$q$, 2, ARRAY[$q$SPIP is an open-source content management system built specifically around collaborative editorial workflows. Rather than being a general-purpose website builder, it was designed from the start for teams of writers and editors who need to structure, review, and publish articles together, with built-in roles for authors, editors, and administrators.$q$, $q$Since its 2001 launch, SPIP has grown into a mature platform with a large plugin catalog and an active community, primarily in France and the wider French-speaking world, though it is used internationally and translated into more than 20 languages. It remains free under the GNU GPL, with no paid tiers or licensing fees for the core software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SPIP's core strength is its editorial workflow: articles move through draft, proposed, and published states, with role-based permissions that let editorial teams collaborate without stepping on each other's work. Its templating system, built on a custom language called SPIP loops, separates content from presentation, making it possible to restyle a site without touching the underlying data.$q$, $q$The platform also includes native multilingual publishing tools, so a single site can maintain parallel versions of content in different languages with translation tracking. A large community plugin directory extends SPIP with forums, newsletters, e-commerce, SEO helpers, and custom fields, while its lightweight footprint makes it a practical option for organizations that want a self-hosted CMS without the overhead of larger platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SPIP itself is entirely free to download and use, since it is licensed under the GNU General Public License. There are no editions, tiers, or user limits built into the software.$q$, $q$The only real costs are self-hosting related: web hosting, a domain name, and optionally paid support or development from independent SPIP freelancers and agencies in the community, since there is no official commercial vendor offering paid plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7206e3a-e992-4f4e-b237-ddd3af5fbec1', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Real-time multiplayer editing$q$, $q$Multiple team members can design in the same 3D scene simultaneously, with comments and version history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Browser-based 3D modeling$q$, $q$Model, texture, and animate 3D objects directly in the browser without installing desktop 3D software.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Interactive and physics-based scenes$q$, $q$Add click, scroll, and hover interactions and physics behaviors to 3D objects for interactive web experiences.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Code and web export$q$, $q$Export scenes as embeddable web widgets, React components, images, or video for use in any website or app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$AI 3D generation add-on$q$, $q$Generate 3D assets and textures from text or image prompts using the optional Spline AI add-on.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Material and asset libraries$q$, $q$Access built-in libraries of materials, audio, and templates to speed up scene building.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Framework and platform integrations$q$, $q$Works alongside tools like Framer and Webflow to bring interactive 3D into existing web projects.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Runs entirely in the browser with no heavy desktop 3D software required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Real-time collaboration makes it easy for design teams to work together$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Flexible export options including code, video, image, and embeddable widgets$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Generous free plan for exploring 3D design before upgrading$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$AI-assisted 3D and texture generation speeds up asset creation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Free plan exports carry a visible watermark$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Advanced features like code export and APIs require the Professional tier or higher$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Steeper learning curve for users with no prior 3D design experience$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Complex scenes can be demanding on browser performance$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Enterprise features like SSO require custom-priced plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Is Spline free to use$q$, $q$Yes. Spline offers a free plan with limited files and watermarked web exports, with paid plans starting at $12 per month per editor for unlimited files and no watermark.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Do I need 3D design experience to use Spline$q$, $q$No prior 3D experience is required, though there is a learning curve. Spline is designed to be more approachable than traditional 3D software like Blender or Cinema 4D.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Can Spline scenes be embedded on a website$q$, $q$Yes. Spline scenes can be embedded directly into websites, exported as code components, or rendered as static images and video.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Does Spline support real-time collaboration$q$, $q$Yes. Spline supports real-time multiplayer editing, similar to collaborative 2D design tools, so multiple people can work on a scene at once.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$What is the Spline AI add-on$q$, $q$Spline AI is an optional add-on, priced at $5 per seat per month, that generates 3D models and textures from text or image prompts using AI.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Who founded Spline$q$, $q$Spline was founded in 2020 by Alejandro Leon, Andrei Linkov, and Vadim Konstantinov and is backed by Y Combinator.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$What can Spline be used for$q$, $q$Spline is commonly used to create interactive product visuals, animated landing pages, 3D web experiences, and design prototypes.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Does Spline offer an enterprise plan$q$, $q$Yes. Spline Enterprise offers custom pricing with SAML SSO, self-hosted exports, version history, and priority support.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Interactive marketing and product pages$q$, $q$Marketing and design teams build animated 3D visuals and product showcases to increase engagement on landing pages.$q$, $q$Marketing and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Product design prototyping$q$, $q$Product designers create interactive 3D prototypes and UI concepts before handing them to engineering.$q$, $q$Product and UX designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Developer-integrated 3D web experiences$q$, $q$Developers export Spline scenes as code components to embed interactive 3D directly into React and other web apps.$q$, $q$Front-end developers and creative technologists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Free$q$, $q$$0/month$q$, $q$N/A$q$, NULL, $q$["Limited files","Unlimited viewers","Watermarked web exports","Access to Spline templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Starter$q$, $q$$12/month per editor (billed annually) or $15/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited 3D and 2D files","No watermark on web exports","Video uploads","Higher resolution image exports","Material and audio libraries"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Professional$q$, $q$$20/month per editor (billed annually) or $25/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Starter","Unlimited scenes per file","Code export","Apple and Android exports","Unlimited variables, APIs, and webhooks","2D editor"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Everything in Professional","Centralized licensing and billing","SAML SSO","Self-hosted exports","File version history","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$overview$q$, $q$What Is Spline$q$, 2, ARRAY[$q$Spline is a real-time, browser-based 3D design tool built to make interactive 3D content as accessible as 2D design tools like Figma. Instead of requiring a full desktop 3D application and rendering pipeline, Spline lets teams model, texture, animate, and publish 3D scenes directly from a web browser.$q$, $q$Founded in 2020 and headquartered in San Francisco, Spline has grown into a widely used tool among product designers, marketing teams, and developers who want to add interactive 3D elements to websites, apps, and product pages without hiring specialist 3D artists for every project.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Spline combines 3D modeling primitives, a material and texture library, and physics-based interactions in a single editor, so users can build objects that respond to clicks, scroll, or cursor movement. Its real-time multiplayer editing lets multiple designers work on the same scene simultaneously, with comments and version history similar to modern collaborative design tools.$q$, $q$Export options are a major part of Spline's workflow: scenes can be embedded directly into websites, exported as code components for React and other frameworks, or rendered as static images and video. The optional Spline AI add-on adds text-to-3D and image-to-3D generation, letting users create base 3D assets from prompts or reference images rather than modeling from scratch.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdd5fb34-6747-4479-81aa-8ae793ce0279', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Spline uses a per-seat freemium pricing model. The Free plan allows a limited number of files with unlimited viewers, but web exports carry a Spline watermark. The Starter plan, from $12 per month per editor billed annually, removes the watermark and unlocks unlimited files and folders.$q$, $q$The Professional plan, from $20 per month per editor billed annually, adds unlimited scenes per file, code export, and API and webhook access, while Enterprise pricing is custom and includes SAML SSO, self-hosted exports, and priority support. The Spline AI add-on is available for an additional $5 per seat per month with a monthly AI credit allowance.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$AI-assisted contract review$q$, $q$Flags risky clauses and extracts key terms automatically to speed up contract review and negotiation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Template-based contract drafting$q$, $q$Standardized templates and an in-app editor help teams generate consistent contracts quickly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Native e-signature$q$, $q$Built-in digital signature capability removes the need for a separate e-signature tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Configurable approval workflows$q$, $q$Route contracts through custom approval chains based on contract type, value, or department.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Searchable contract repository$q$, $q$Centralized, searchable storage for all executed and in-progress contracts with metadata tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Clickthrough agreements$q$, $q$A dedicated module for managing high-volume click-to-accept agreements like terms of service.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Obligation and renewal tracking$q$, $q$Automatically extracts dates and obligations to alert teams ahead of renewals or expirations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$CRM and workflow integrations$q$, $q$Connects with tools such as Salesforce and Slack to embed contract workflows into existing systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$AI-assisted review can meaningfully cut contract turnaround time$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$All-in-one platform covering drafting, signature, and repository$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Implementation and support included without extra fees$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Flexible pricing based on users or contract volume$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Backed by significant funding and reports of profitability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$No public pricing, requiring a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$No free trial or self-serve evaluation option$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Custom quotes can make budgeting harder for smaller teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Primarily suited to companies with an in-house legal function$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Full feature depth may be more than very small teams need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$What is SpotDraft used for$q$, $q$SpotDraft is used for contract lifecycle management, covering drafting, negotiation, e-signature, approval workflows, and ongoing contract tracking in one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$How much does SpotDraft cost$q$, $q$SpotDraft does not publish fixed pricing. It uses a custom quote-based model priced per user or by contract volume, with third-party estimates suggesting annual contracts often start around ten thousand dollars.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Where is SpotDraft headquartered$q$, $q$SpotDraft is headquartered in Bengaluru, India, with an additional office in New York.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Does SpotDraft offer a free trial$q$, $q$No. SpotDraft does not offer a public free trial or self-serve signup; prospective customers go through a sales demo process.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Does SpotDraft include e-signature$q$, $q$Yes. SpotDraft includes a native e-signature capability so contracts can be signed without a separate tool.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Who founded SpotDraft$q$, $q$SpotDraft was founded in 2017 by Shashank Bijapur and Madhav Bhagat.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$What integrations does SpotDraft support$q$, $q$SpotDraft integrates with tools such as Salesforce and Slack to connect contract workflows with existing sales and communication systems.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Who is SpotDraft best suited for$q$, $q$SpotDraft is best suited for small and mid-market businesses with in-house legal teams, though it also supports larger enterprise customers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$In-house legal contract management$q$, $q$Legal teams centralize drafting, redlining, and storage of contracts to reduce manual tracking in spreadsheets and email.$q$, $q$In-house legal and general counsel teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Sales contract acceleration$q$, $q$Sales operations teams use standardized templates and automated approvals to close customer contracts faster.$q$, $q$Sales operations and revenue teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$High-volume clickthrough agreements$q$, $q$Companies manage terms of service and click-to-accept agreements at scale using the Clickthrough module.$q$, $q$Product and compliance teams managing online agreements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$Custom (Quote-Based)$q$, $q$Custom pricing$q$, $q$Monthly or annual$q$, NULL, $q$["Priced per active user or by contract volume","Contract templates and AI-assisted drafting","Native e-signature","Implementation and workflow setup included","Dedicated account manager","24 by 7 customer support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$overview$q$, $q$What Is SpotDraft$q$, 2, ARRAY[$q$SpotDraft is a contract lifecycle management platform designed to take contracts from first draft through signature and ongoing management inside a single system. It targets in-house legal teams, along with the sales and procurement teams that generate and request contracts, aiming to reduce the back-and-forth typically involved in contract review.$q$, $q$Founded in 2017 and based in Bengaluru, India, SpotDraft has positioned itself as an AI-native CLM, building AI-assisted drafting and review into its core workflow rather than adding it as a bolt-on feature. The company has raised over 80 million dollars in venture funding and reports being profitable.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SpotDraft centers on a contract repository with searchable metadata, template-based drafting, and an in-app editor for redlining and negotiation. Its AI features assist with reviewing incoming contracts, flagging risky clauses, and extracting key terms and dates for tracking obligations and renewals.$q$, $q$The platform also includes native e-signature, configurable approval workflows for routing contracts to the right stakeholders, and Clickthrough, a module for managing high-volume click-to-accept agreements such as terms of service. Integrations with tools like Salesforce and Slack connect contract workflows to existing sales and communication systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e12cbfc9-d246-4893-93a6-78ac5fffa567', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SpotDraft does not publish fixed pricing tiers on its website. Instead, it uses a custom quote-based model, with plans priced either per active user per month or year, or based on contract volume for organizations with variable or seasonal usage.$q$, $q$Implementation, workflow setup, integrations, and support are included in the quoted price with no separate add-on fees. Third-party pricing guides estimate typical annual contracts starting in the range of ten thousand dollars and scaling with company size and feature needs, though exact figures require a sales conversation with SpotDraft.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Unified virtual, hybrid, and in-person events$q$, $q$Run any event format from a single platform rather than switching tools by event type.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$80+ engagement features$q$, $q$Includes polls, Q and A, gamification, networking, and breakout sessions to drive attendee engagement.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Live streaming and speaker studio$q$, $q$Built-in broadcast studio tools support professional live streaming directly from the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Unlimited participants and admins$q$, $q$Pricing is not based on attendee count, allowing events to scale without per-attendee fees.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Life sciences compliance support via Onomi$q$, $q$A dedicated offering addresses compliant customer engagement for regulated life sciences interactions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Marketing and CRM integrations$q$, $q$Connects with tools like Marketo and Cvent on higher-tier plans for lead and registration data flow.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Branded native apps$q$, $q$Enterprise customers can publish their own branded app in the App Store and Google Play.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$24/7 customer support$q$, $q$SpotMe offers round-the-clock support with a stated 30-second response target across plans.$q$, 7);
