INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Number of events per year is capped on lower-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Advanced integrations and branded apps are limited to higher tiers$q$, 2);
