INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$May be more platform than smaller organizations running occasional events need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$What is SpotMe used for$q$, $q$SpotMe is used to plan and run virtual, hybrid, and in-person enterprise events, including conferences, internal meetings, and life sciences customer engagement events.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$How much does SpotMe cost$q$, $q$SpotMe does not publish fixed pricing. It offers four tiers, Starter, Business, Advanced, and Enterprise, all requiring a custom quote from sales.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Where is SpotMe headquartered$q$, $q$SpotMe is headquartered in Lausanne, Switzerland, with additional offices in Chicago, Sofia, and Singapore.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$When was SpotMe founded$q$, $q$SpotMe was founded in 2000 as a spin-off from EPFL in Lausanne, Switzerland.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Does SpotMe pricing depend on attendee numbers$q$, $q$No. SpotMe states its pricing does not change based on the number of participants in an event.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$What is Onomi$q$, $q$Onomi is SpotMe's event-centric customer engagement offering built specifically for the life sciences industry and its compliance requirements.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Who owns SpotMe$q$, $q$Swiss Post acquired a majority stake in SpotMe in April 2023, while SpotMe continues to operate as an independent company.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Does SpotMe support hybrid events$q$, $q$Yes. SpotMe supports virtual, hybrid, and in-person events from the same platform, including streaming and in-room engagement tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Life sciences customer engagement events$q$, $q$Pharmaceutical and life sciences companies use SpotMe and its Onomi offering to run compliant engagement events with healthcare professionals.$q$, $q$Life sciences and pharmaceutical companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Enterprise conferences and internal events$q$, $q$Large organizations run hybrid conferences, town halls, and training events with unified engagement tools.$q$, $q$Enterprise event and internal communications teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Professional services client events$q$, $q$Consulting and professional services firms use SpotMe to host client-facing events with branded, secure event apps.$q$, $q$Professional services firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Starter$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Up to 2 virtual, hybrid, or in-person events","Unlimited participants and admins","Desktop web plus iOS/Android app","Streaming, breakouts, and speaker studio","80+ engagement features","24/7 support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Business$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Up to 5 events","Everything in Starter","Marketo, Cvent, and 6 additional integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Advanced$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Up to 25 events","Everything in Business","Branded App Store and Google Play app","App single sign-on"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Unlimited events","Everything in Advanced","CMS single sign-on"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$overview$q$, $q$What Is SpotMe$q$, 2, ARRAY[$q$SpotMe is an enterprise event management platform that supports virtual, hybrid, and in-person events from a single system. Originally founded in 2000 as an EPFL spin-off in Lausanne, Switzerland, the company began as a hardware networking device maker before transforming into a SaaS event app platform in 2011.$q$, $q$SpotMe has built a particular focus on regulated industries, especially life sciences, where compliant engagement with healthcare professionals is a major requirement, alongside professional services and technology companies running large internal or customer-facing events.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform offers more than 80 engagement features spanning event apps for desktop, iOS, and Android, live streaming and broadcast studio tools for speakers, breakout sessions, polling, Q and A, and gamification. Its unlimited participants and admins model means pricing is not tied to attendee counts.$q$, $q$For enterprise customers, SpotMe adds integrations with marketing and event tools such as Marketo and Cvent, branded app store and Google Play apps, and single sign-on. Its Onomi offering extends the platform specifically for life sciences customer engagement, addressing compliance needs around interactions with healthcare professionals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f78d10ab-b34b-493a-9c96-2e256f6d8c27', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SpotMe does not publish fixed prices; all four plans, Starter, Business, Advanced, and Enterprise, require contacting sales for a custom quote. Plans are primarily differentiated by the number of events included per year, ranging from up to 2 events on Starter to unlimited events on Enterprise.$q$, $q$A notable aspect of SpotMe's pricing is that it does not increase based on the number of event participants, so organizations can scale attendance without cost surprises. Production add-on services, such as onsite coordination and live production support, are priced separately and start in the range of 3,000 to 7,700 dollars or more per engagement.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Cloud-based POS software$q$, $q$Point-of-sale software for restaurants that runs on countertop terminals and handheld devices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Integrated payment processing$q$, $q$Built-in payment processing with competitive rates paired directly with the POS system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Online ordering and delivery$q$, $q$Online ordering platform that integrates with the POS for a unified order flow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Reservation and waitlist management$q$, $q$Tools for managing table reservations and walk-in waitlists in one system.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Labor scheduling and payroll integration$q$, $q$Staff scheduling tools that connect with payroll to streamline restaurant operations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$AI-powered profitability insights$q$, $q$Analyzes sales and cost data to surface menu and profitability insights for operators.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Marketing and loyalty programs$q$, $q$Built-in tools to run loyalty programs and marketing campaigns to drive repeat customers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$SpotOn Terminal for small businesses$q$, $q$A standalone POS and payments product for non-restaurant small businesses like retail and salons.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Software plans can start at 0 dollars per month$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$All-in-one ecosystem covering POS, payments, ordering, and operations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Ranked number one restaurant POS by G2 for multiple consecutive quarters$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Serves both restaurants and general small businesses via SpotOn Terminal$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Backed by major investors, indicating financial stability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Detailed hardware and software pricing is not published upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Requires a demo or sales conversation to get an accurate quote$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Payment processing rates add to the total cost beyond the software fee$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Primarily optimized for foodservice, with fewer industry-specific features outside restaurants$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Full feature set may be more than very small or single-location operators need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$What is SpotOn used for$q$, $q$SpotOn is used by restaurants and small businesses for point-of-sale operations, payment processing, online ordering, reservations, labor scheduling, and marketing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$How much does SpotOn cost$q$, $q$SpotOn advertises POS software starting as low as 0 dollars per month plus payment processing rates, though most restaurants use the Core Bundle package with pricing that requires a custom quote.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Where is SpotOn headquartered$q$, $q$SpotOn is headquartered in San Francisco, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$When was SpotOn founded$q$, $q$SpotOn was founded in 2017 by Doron Friedman, Matt Hyman, and Zach Hyman.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Does SpotOn work for businesses other than restaurants$q$, $q$Yes. SpotOn Terminal serves general small businesses such as retail stores, salons, and automotive shops, in addition to its core restaurant products.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Does SpotOn include online ordering$q$, $q$Yes. SpotOn offers an online ordering and delivery platform that integrates directly with its POS system.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Is SpotOn a public or private company$q$, $q$SpotOn is privately held, backed by investors including Dragoneer Investment Group, Andreessen Horowitz, 01 Advisors, DST Global, and Franklin Templeton.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Does SpotOn offer payroll features$q$, $q$Yes. SpotOn includes labor scheduling with payroll integration as part of its restaurant management tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Full-service restaurant operations$q$, $q$Casual and fine dining restaurants use SpotOn for tableside POS, reservations, and staff scheduling in one system.$q$, $q$Full-service restaurants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Quick-service and cafe ordering$q$, $q$Quick-service restaurants and cafes use SpotOn for fast checkout, online ordering, and kitchen display coordination.$q$, $q$Quick-service restaurants and cafes$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$General small business payments$q$, $q$Retail, salon, and automotive businesses use SpotOn Terminal for POS and payment processing outside foodservice.$q$, $q$Retail and service-based small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$Core Bundle$q$, $q$From $0/month software (plus payment processing rates)$q$, $q$Monthly$q$, NULL, $q$["Cloud-based POS software","Payment processing","Online ordering integration","Reservation and waitlist tools","Custom hardware and add-on pricing via quote"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$overview$q$, $q$What Is SpotOn$q$, 2, ARRAY[$q$SpotOn is a restaurant and small-business technology company that combines point-of-sale hardware, payment processing, and back-office management software into a single ecosystem. It was founded in 2017 and is headquartered in San Francisco, California.$q$, $q$While SpotOn's primary focus is foodservice, spanning casual dining, fine dining, bars, breweries, quick-service, and cafes, it also serves general small businesses such as retail stores, salons, and automotive shops through SpotOn Terminal, a standalone POS and payments product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SpotOn's restaurant platform includes cloud-based POS software, countertop terminals, handheld ordering devices, and kitchen display systems, alongside online ordering and delivery integration. Operational tools cover reservation and waitlist management, labor scheduling, and payroll integration, helping restaurants manage both the front and back of house.$q$, $q$On top of transaction processing, SpotOn provides marketing and loyalty programs to help restaurants drive repeat business, plus AI-powered profitability analysis that surfaces menu and cost insights. The platform has been recognized as the number one restaurant POS by G2 for six consecutive quarters.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17484540-c7ef-4a3f-b23f-5866c0cdd5ac', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SpotOn advertises its POS software plans as starting as low as 0 dollars per month, paired with competitive payment processing rates rather than a flat software fee. Most restaurants adopt SpotOn's Core Bundle package, which combines hardware, software, and payment processing.$q$, $q$Exact software and hardware pricing is not published in detail and typically requires requesting a demo or quote from SpotOn's sales team, since costs vary based on business type, transaction volume, and the specific hardware and add-on modules selected.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$RSS feed hosting and management$q$, $q$Manage and customize a podcast's RSS feed directly within Spreaker's dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Automatic multi-platform distribution$q$, $q$Episodes are automatically distributed to major platforms including Spotify and Apple Podcasts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Built-in ad monetization$q$, $q$Automatic ad insertion lets creators earn revenue without arranging sponsorships manually.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Supporters Club subscriptions$q$, $q$A membership feature that lets listeners directly support a show with recurring payments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Listener analytics and statistics$q$, $q$Tracks listener numbers and engagement, with historical statistics ranging from 6 to 24 months depending on plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Live broadcasting tools$q$, $q$Supports live streaming and broadcasting in addition to standard episode publishing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Team collaboration$q$, $q$Higher-tier plans support unlimited collaborators for teams producing a show together.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Direct ad sales tools$q$, $q$The Publisher plan includes an ad campaign manager and IAB category blocking for professional advertisers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Generous free-forever plan with unlimited episodes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Backed by iHeartMedia, providing scale and monetization infrastructure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Built-in monetization tools including ads and listener subscriptions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Simple, dashboard-based workflow for publishing and distribution$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Scales from individual creators up to professional broadcasters$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Free plan limits hosting to a single podcast$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Free plan takes a 20 percent cut of Supporters Club revenue$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Higher-tier plans needed for extended statistics history and collaboration$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Pricing is listed in euros, which may complicate budgeting for some regions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Top-tier Publisher plan is priced well above typical independent creator budgets$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Is Spreaker free$q$, $q$Yes. Spreaker offers a free-forever Free Speech plan with unlimited episodes and automatic ad monetization, though it hosts only one podcast.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Who owns Spreaker$q$, $q$Spreaker is owned by iHeartMedia, which acquired its parent company Voxnest, formed from the 2018 merger of Spreaker and BlogTalkRadio, in 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$When was Spreaker founded$q$, $q$Spreaker was founded in 2010 by Francesco Baschieri.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$How does Spreaker monetization work$q$, $q$Spreaker supports monetization through automatic ad insertion, listener subscriptions, and a Supporters Club membership feature, with direct ad sales tools on the Publisher plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$What is the cheapest paid Spreaker plan$q$, $q$The Broadcaster plan is the cheapest paid tier at 20 euros per month, offering unlimited podcasts and removing the Supporters Club fee.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Does Spreaker support live broadcasting$q$, $q$Yes. Spreaker supports live streaming and broadcasting in addition to standard episode publishing and distribution.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Can I upgrade my Spreaker plan later$q$, $q$Yes. Spreaker allows users to start on a lower plan and upgrade at any time, with prorated billing.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Who is Spreaker best suited for$q$, $q$Spreaker suits independent podcasters wanting simple free hosting, as well as professional broadcasters and media companies needing advanced monetization and ad sales tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Independent podcast creators$q$, $q$Individual creators use the free plan to publish, distribute, and monetize a podcast with no upfront cost.$q$, $q$Independent and hobbyist podcasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Professional broadcasters and media companies$q$, $q$Broadcasters use higher-tier plans for direct ad sales, extended analytics, and team collaboration on shows.$q$, $q$Media companies and professional broadcasters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Live radio and streaming shows$q$, $q$Hosts use Spreaker's live broadcasting tools to stream radio-style shows alongside standard podcast episodes.$q$, $q$Live radio and streaming show hosts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Free Speech$q$, $q$EUR0/month$q$, $q$Free forever$q$, NULL, $q$["1 podcast","6 months of statistics","Unlimited episodes","Automatic ad monetization","Auto-upload to major platforms","20 percent Supporters Club fee"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Broadcaster$q$, $q$EUR20/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited podcasts","12 months of statistics","Ads and subscription monetization","Enhanced private podcasts","0 percent Supporters Club fee"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Anchorman$q$, $q$EUR50/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited podcasts and collaborators","12 months of statistics","Customizable player colors","Full statistics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$Publisher$q$, $q$EUR250/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited podcasts and collaborators","24 months of statistics","Priority support","Ad campaign manager for direct ad sales","IAB category blocking"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$overview$q$, $q$What Is Spreaker$q$, 2, ARRAY[$q$Spreaker is a podcast hosting platform that lets creators publish, distribute, and monetize podcasts from a single dashboard. It was founded in 2010 by Francesco Baschieri and later merged with BlogTalkRadio in 2018 to form Voxnest, which iHeartMedia acquired in 2020.$q$, $q$Today Spreaker operates as part of iHeartMedia's podcast infrastructure, serving both independent podcasters looking for simple, reliable hosting and larger broadcasters and media companies that need enterprise-scale distribution and ad monetization tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Spreaker manages a show's RSS feed and automatically distributes episodes to major listening platforms, while providing listener analytics and a customizable embeddable player. Monetization tools include automatic ad insertion, subscription support, and a Supporters Club feature for direct listener support.$q$, $q$Higher-tier plans add collaboration features for teams producing a show together, extended historical statistics, and, on the Publisher plan, an ad campaign manager for selling ads directly along with IAB category blocking to control which ad categories appear on a show.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41ee4232-5722-4e22-a602-9fdc2ae29ca2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Spreaker's Free Speech plan is free forever and includes unlimited episodes, automatic ad monetization, and 6 months of statistics, but hosts only one podcast and takes a 20 percent fee on Supporters Club revenue.$q$, $q$Paid plans start at the Broadcaster tier for 20 euros per month, offering unlimited podcasts and 12 months of statistics with no Supporters Club fee, scaling up through Anchorman at 50 euros per month for unlimited collaborators and full statistics, to Publisher at 250 euros per month for professional broadcasters needing direct ad sales tools and 24 months of statistics.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Headless architecture with REST APIs$q$, $q$Storefront and admin REST APIs let developers build custom front ends on any framework.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Next.js storefront and TypeScript SDK$q$, $q$A production-ready Next.js storefront and TypeScript SDK speed up building a modern headless front end.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Self-hosted, no vendor lock-in$q$, $q$Fully self-hostable with no mandatory platform fees or dependency on a single vendor's infrastructure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Multi-region and multi-currency support$q$, $q$Native support for multiple regions, currencies, and languages within a single store setup.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Sales channels and order routing$q$, $q$Configure per-channel catalogs and rules-based order routing across sales channels.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Stock reservations$q$, $q$Built-in stock reservation logic helps manage inventory accurately across orders and channels.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$B2B and marketplace modules (Enterprise)$q$, $q$Paid add-on modules extend Spree with B2B commerce and multi-vendor marketplace capabilities.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Enterprise security and support$q$, $q$Enterprise Edition adds SSO, audit logging, role-based access control, and SLA-backed support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Community Edition is completely free and open source with no platform fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Full ownership of the commerce stack with no vendor lock-in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Built on Ruby on Rails with a mature, long-standing codebase since 2007$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Modern headless architecture with REST APIs and a Next.js storefront$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Large open-source contributor base and proven use by major brands$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Self-hosting requires developer resources and Ruby on Rails expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Community Edition is limited to direct-to-consumer use, not B2B or marketplace$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Enterprise Edition pricing is not published and requires a custom quote$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$No official managed hosting from Spree itself, requiring third-party infrastructure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Smaller ecosystem compared to hosted platforms like Shopify$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Is Spree Commerce free$q$, $q$Yes. The Spree Commerce Community Edition is free and open source under the BSD-3-Clause license, available for self-hosting at no cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$What is the difference between Spree Community and Enterprise Edition$q$, $q$Community Edition is a free, self-hosted, direct-to-consumer commerce engine, while Enterprise Edition is commercially licensed and adds B2B, multi-vendor marketplace, and multi-tenant modules plus dedicated support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$What technology is Spree Commerce built on$q$, $q$Spree Commerce is built on Ruby on Rails, with REST APIs, a TypeScript SDK, and a production-ready Next.js storefront available for headless front ends.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Who created Spree Commerce$q$, $q$Spree Commerce was created by Sean Schofield in 2007 and has since grown through contributions from over 800 developers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Does Spree Commerce support multiple currencies and languages$q$, $q$Yes. Spree natively supports multi-region, multi-currency, and multi-language store configurations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Is Spree Commerce suitable for B2B ecommerce$q$, $q$The free Community Edition is direct-to-consumer only; B2B commerce capabilities are available through the paid Enterprise Edition.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Who maintains Spree Commerce today$q$, $q$Spree Commerce is currently maintained and developed by a team operating as Vendo, following its 2015 acquisition by First Data.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$What companies use Spree Commerce$q$, $q$Companies that have used Spree Commerce include Goop, Blue Bottle Coffee, Fortnum and Mason, Craftsman, Kenmore, and GoDaddy.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Developer-built custom storefronts$q$, $q$Development teams use Spree's REST APIs and Next.js storefront to build fully custom, headless shopping experiences.$q$, $q$Developers and technical teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Self-hosted DTC brands$q$, $q$Growing direct-to-consumer brands use the free Community Edition to avoid recurring platform fees while owning their stack.$q$, $q$Direct-to-consumer ecommerce brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$B2B and marketplace commerce$q$, $q$Enterprises needing multi-vendor marketplace or B2B ordering use the paid Enterprise Edition modules on top of Spree's core.$q$, $q$Enterprises and marketplace operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","BSD-3-Clause open-source license","Full storefront, catalog, and checkout","Storefront and admin REST APIs","Multi-region, multi-currency, multi-language support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$Enterprise Edition$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Self-hosted or private cloud options","B2B and marketplace add-on modules","Multi-tenant white-label SaaS module","Dedicated success manager","SLA-backed support and 24/7 monitoring","SSO, audit logging, and role-based access control"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$overview$q$, $q$What Is Spree Commerce$q$, 2, ARRAY[$q$Spree Commerce is an open-source, headless e-commerce platform built on Ruby on Rails, created by Sean Schofield in 2007. It gives developers a fully self-hostable commerce engine with no vendor lock-in and no mandatory platform fees, since the core Community Edition is licensed under BSD-3-Clause.$q$, $q$The project has grown through more than 800 contributors and has been used by well-known brands such as Goop, Blue Bottle Coffee, and Fortnum and Mason. Following its 2015 acquisition by First Data, the project has continued as an actively maintained open-source platform, with a team operating as Vendo now driving its development and offering a commercial Enterprise Edition.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Spree provides a complete commerce engine out of the box: product catalog, storefront, checkout, and both storefront and admin REST APIs, along with a TypeScript SDK and a production-ready Next.js storefront for teams that want a modern headless front end. It natively supports multi-region, multi-currency, and multi-language stores.$q$, $q$Because it is self-hosted, teams own their full stack and data, and can customize checkout flows, catalogs, and integrations without waiting on a vendor roadmap. The paid Enterprise Edition builds on this foundation with B2B commerce, multi-vendor marketplace, and multi-tenant white-label SaaS modules for companies that need those capabilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The Spree Commerce Community Edition is completely free and open source under the BSD-3-Clause license, with no fees for self-hosting, unlimited stores, or unlimited transactions since there is no vendor billing relationship for the core software.$q$, $q$The Enterprise Edition is commercially licensed with custom pricing available on request, adding paid add-on modules for B2B, multi-vendor marketplace, and multi-tenant white-label SaaS, along with dedicated support, SLA-backed response times, and enterprise security features such as SSO and audit logging.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80d28886-f2f5-4191-a617-3ed3234eb862', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01db3fa1-4544-4df3-b94a-c8779f0ed121', $q$Automated evidence collection$q$, $q$Continuously collects timestamped evidence from connected systems instead of requiring manual screenshots before audits.$q$, 0);
